// ========================================
// EDIT THESE 4 VALUES with your actual API keys
// ========================================
return [{json: {
  clickupToken: 'pk_YOUR_CLICKUP_TOKEN',
  clickupListId: 'YOUR_LIST_ID',
  serperApiKey: 'YOUR_SERPER_KEY',
  claudeApiKey: 'sk-ant-YOUR_CLAUDE_KEY'
}}];

var config = $('Config').first().json;
var resp = $input.first().json;
var tasks = resp.tasks || [];

if (!tasks.length) {
  throw new Error('No tasks found in ClickUp list. Check your list ID.');
}

return tasks.map(function(t) {
  return {json: {
    clickupToken: config.clickupToken,
    serperApiKey: config.serperApiKey,
    claudeApiKey: config.claudeApiKey,
    taskId: t.id,
    taskName: t.name || 'Unnamed task',
    taskDescription: t.text_content || t.description || 'No description',
    taskStatus: t.status ? t.status.status : 'unknown',
    taskPriority: t.priority ? t.priority.priority : 'none',
    taskUrl: t.url || ''
  }};
});

var task = $('Extract Tasks').item.json;
var search = $input.item.json;

// Extract top search results
var organic = search.organic || [];
var results = organic.slice(0, 5).map(function(r) {
  return '- ' + (r.title || '') + ': ' + (r.snippet || '');
}).join('\n');

// Build the briefing prompt
var lines = [
  'Du ar en AI-forskningsassistent for ett svenskt livforsakringsjamforelseprojekt.',
  '',
  'Uppgift fran ClickUp:',
  '- Namn: ' + task.taskName,
  '- Beskrivning: ' + task.taskDescription,
  '- Status: ' + task.taskStatus,
  '- Prioritet: ' + task.taskPriority,
  '',
  'Sokresultat fran webben:',
  results || 'Inga sokresultat tillgangliga.',
  '',
  'Skapa en kort brief (pa svenska) med foljande struktur:',
  '',
  '1. **Sammanfattning** - Vad handlar uppgiften om?',
  '2. **Bakgrundsforskning** - Relevanta fynd fran webben och din egen kunskap',
  '3. **Rekommendation** - Konkreta steg for hur vi bor ga tillvaga',
  '4. **Risker/Utmaningar** - Vad kan ga fel?',
  '5. **Nasta steg** - Vad bor goras forst?',
  '',
  'Hall det kort och konkret. Max 500 ord.'
];

var prompt = lines.join('\n');

// Build Claude API request body
var body = JSON.stringify({
  model: 'claude-sonnet-4-20250514',
  max_tokens: 2048,
  messages: [{role: 'user', content: prompt}]
});

return [{json: {
  taskId: task.taskId,
  taskName: task.taskName,
  clickupToken: task.clickupToken,
  claudeApiKey: task.claudeApiKey,
  requestBody: body
}}];

var task = $('Build Brief Prompt').item.json;
var resp = $input.item.json;

// Extract brief text from Claude response
var brief = 'Could not generate brief.';
if (resp.content && resp.content[0] && resp.content[0].text) {
  brief = resp.content[0].text;
}

// Format as ClickUp comment
var comment = '[AI Brief] ' + task.taskName + '\n\n' + brief;

return [{json: {
  taskId: task.taskId,
  clickupToken: task.clickupToken,
  commentBody: JSON.stringify({comment_text: comment})
}}];
